import re
rules = [(r'password|credential|secret','credentials'),(r'rm\s+-rf|drop\s+table','destructive'),(r'hack|exploit','offensive')]
def guardrail(text):
    for pat, name in rules:
        if re.search(pat, text, re.I):
            return f'FLAGGED({name})'
    return 'ALLOWED'
for t in ['Analyze log file','Remove password from config','How to secure SSH','Drop table cleanup']:
    print(f'[{guardrail(t):25s}] {t}')
